import{_ as e,c as a,o as s,a4 as t}from"./chunks/framework.BmdFiWrL.js";const k=JSON.parse('{"title":"Frontend Real IP Header Configuration","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/q12.md","filePath":"en_US/guide/q12.md","lastUpdated":1780405010000}'),i={name:"en_US/guide/q12.md"},n=t(`<h1 id="frontend-real-ip-header-configuration" tabindex="-1">Frontend Real IP Header Configuration <a class="header-anchor" href="#frontend-real-ip-header-configuration" aria-label="Permalink to &quot;Frontend Real IP Header Configuration&quot;">​</a></h1><p>The <strong>Frontend Real IP Request Header</strong> lets Dashboard identify the real client IP of visitors accessing the admin frontend and user frontend. Online users, login brute-force protection, OAuth2 brute-force protection, API Token brute-force protection, Agent connection-secret brute-force protection, audit records, and the Web Application Firewall (WAF) all rely on this IP.</p><p>Configure this in the admin frontend under <strong>avatar → System Settings → System Configuration → Frontend Real IP Request Header</strong>. The corresponding configuration file field is <a href="/en_US/configuration/dashboard.html#web_real_ip_header"><code>web_real_ip_header</code></a>.</p><div class="warning custom-block"><p class="custom-block-title">Frontend and Agent headers are different</p><p>The <strong>Frontend Real IP Request Header</strong> only applies to browser or user access to Dashboard. The <strong>Agent Real IP Request Header</strong> only applies to Agent connections to Dashboard. Their entry points, proxy chains, and purposes may be different. Do not mix them.</p></div><hr><h2 id="what-to-use" tabindex="-1">What to Use <a class="header-anchor" href="#what-to-use" aria-label="Permalink to &quot;What to Use&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Deployment</th><th>Recommended value</th><th>Notes</th></tr></thead><tbody><tr><td>Dashboard directly exposed to the public network</td><td><strong>Use Direct IP</strong></td><td>Equivalent to <code>web_real_ip_header: &quot;NZ::Use-Peer-IP&quot;</code></td></tr><tr><td>Common reverse proxy</td><td><code>X-Real-IP</code> or <code>nz-realip</code> from the reverse proxy examples</td><td>The upstream Nginx, Caddy, Apache, or other proxy must pass the same header</td></tr><tr><td>Cloudflare CDN</td><td><code>CF-Connecting-IP</code></td><td>For other CDNs, use the real-IP header provided by that CDN</td></tr><tr><td>Not sure whether the proxy passes the header correctly</td><td>Leave it empty first, or use direct IP</td><td>Enable a custom header only after checking proxy logs and headers</td></tr></tbody></table><p>Only trust real-IP headers from trusted reverse proxies or CDNs. If users can bypass the proxy and reach Dashboard directly, they may forge this header and cause WAF false positives or bypasses.</p><hr><h2 id="scenario-1-direct-public-access-to-dashboard" tabindex="-1">Scenario 1: Direct Public Access to Dashboard <a class="header-anchor" href="#scenario-1-direct-public-access-to-dashboard" aria-label="Permalink to &quot;Scenario 1: Direct Public Access to Dashboard&quot;">​</a></h2><p>If browsers access Dashboard directly without Nginx, Caddy, Apache, Cloudflare, or another CDN in front of it, select <strong>Use Direct IP</strong>.</p><p>The equivalent configuration file value is:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NZ::Use-Peer-IP&quot;</span></span></code></pre></div><p>In this mode, Dashboard uses the connection IP directly and does not need an upstream application to pass a request header.</p><hr><h2 id="scenario-2-nginx-caddy-apache-or-another-reverse-proxy" tabindex="-1">Scenario 2: Nginx, Caddy, Apache, or Another Reverse Proxy <a class="header-anchor" href="#scenario-2-nginx-caddy-apache-or-another-reverse-proxy" aria-label="Permalink to &quot;Scenario 2: Nginx, Caddy, Apache, or Another Reverse Proxy&quot;">​</a></h2><p>When Dashboard is behind a reverse proxy, the connection IP seen by Dashboard is usually the reverse proxy server&#39;s IP. You need the reverse proxy to write the client IP into a header, then set <strong>Frontend Real IP Request Header</strong> in Dashboard to the same header name.</p><p>Common choices:</p><ul><li>Use the common <code>X-Real-IP</code> header.</li><li>If you follow the <a href="/en_US/guide/q3.html">Reverse Proxy Configuration</a> examples in this documentation, you can use <code>nz-realip</code>.</li><li>If you use <code>X-Forwarded-For</code>, make sure the proxy chain is trusted and confirm Dashboard reads the expected client IP.</li></ul><h3 id="minimal-nginx-example" tabindex="-1">Minimal Nginx Example <a class="header-anchor" href="#minimal-nginx-example" aria-label="Permalink to &quot;Minimal Nginx Example&quot;">​</a></h3><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:8008;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Set Dashboard to:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;X-Real-IP&quot;</span></span></code></pre></div><p>If you use the <code>nz-realip</code> example from the documentation:</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nz-realip $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:8008;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Set Dashboard to:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nz-realip&quot;</span></span></code></pre></div><h3 id="minimal-caddy-example" tabindex="-1">Minimal Caddy Example <a class="header-anchor" href="#minimal-caddy-example" aria-label="Permalink to &quot;Minimal Caddy Example&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com {</span></span>
<span class="line"><span>    reverse_proxy 127.0.0.1:8008 {</span></span>
<span class="line"><span>        header_up X-Real-IP {remote_host}</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Set Dashboard to:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;X-Real-IP&quot;</span></span></code></pre></div><hr><h2 id="scenario-3-cloudflare-or-another-cdn" tabindex="-1">Scenario 3: Cloudflare or Another CDN <a class="header-anchor" href="#scenario-3-cloudflare-or-another-cdn" aria-label="Permalink to &quot;Scenario 3: Cloudflare or Another CDN&quot;">​</a></h2><p>When Dashboard is proxied by Cloudflare, set Dashboard to:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CF-Connecting-IP&quot;</span></span></code></pre></div><p>For other CDNs, use the real client IP header provided by that CDN, such as the Real IP, Client IP, or Connecting IP header described in the vendor documentation.</p><p>Make sure only the trusted CDN or reverse proxy can access the Dashboard origin. If the origin is still directly reachable from the public network, attackers can bypass the CDN and forge the header.</p><hr><h2 id="how-waf-uses-this-ip" tabindex="-1">How WAF Uses This IP <a class="header-anchor" href="#how-waf-uses-this-ip" aria-label="Permalink to &quot;How WAF Uses This IP&quot;">​</a></h2><p>Dashboard&#39;s built-in WAF records risky behavior by <strong>IP + block identifier</strong>. WAF records and blocks a source when any of these events occur:</p><ul><li>Too many failed login attempts.</li><li>OAuth2 login brute force.</li><li>API Token brute force.</li><li>Agent connection secret brute force.</li><li>Manual block by an administrator on the Online Users page.</li></ul><p>The more times the same entry is recorded, the longer the block duration becomes. Administrators can go to <strong>System Settings → Web Application Firewall</strong> to view blocked IPs, block identifiers, counts, reasons, and times, and can delete one or multiple block entries.</p><hr><h2 id="what-happens-if-it-is-misconfigured" tabindex="-1">What Happens If It Is Misconfigured <a class="header-anchor" href="#what-happens-if-it-is-misconfigured" aria-label="Permalink to &quot;What Happens If It Is Misconfigured&quot;">​</a></h2><p>If you set a header that does not exist, is not trusted, or is not passed by the proxy, these problems may occur:</p><ul><li>Dashboard cannot obtain the IP, making online users and audit records inaccurate.</li><li>All visitors are identified as the reverse proxy or CDN IP, causing multiple users to share one block record.</li><li>Users can forge the header to bypass WAF or cause another IP to be blocked by mistake.</li><li>The administrator&#39;s own IP may be blocked by mistake, preventing access to the backend.</li></ul><p>If you are unsure, leave this setting empty or select <strong>Use Direct IP</strong> first. Enable a custom header only after confirming that the reverse proxy passes the correct header.</p><hr><h2 id="how-to-verify" tabindex="-1">How to Verify <a class="header-anchor" href="#how-to-verify" aria-label="Permalink to &quot;How to Verify&quot;">​</a></h2><p>After saving the configuration and restarting Dashboard, verify it this way:</p><ol><li>Visit Dashboard with a browser.</li><li>Go to <strong>System Settings → Online Users</strong> and check whether your IP is the real public client IP, not the reverse proxy, CDN, or an internal address.</li><li>Check the reverse proxy access logs and confirm the client IP matches the IP shown on Dashboard&#39;s Online Users page.</li><li>If possible, temporarily log the header passed from the reverse proxy to Dashboard and confirm the header name and value exactly match <code>web_real_ip_header</code>.</li></ol><p>Do not intentionally test WAF by repeatedly entering wrong passwords, as this may block you or other users by mistake.</p><hr><h2 id="how-to-recover" tabindex="-1">How to Recover <a class="header-anchor" href="#how-to-recover" aria-label="Permalink to &quot;How to Recover&quot;">​</a></h2><p>If a wrong configuration causes abnormal IP detection or prevents login:</p><ol><li><p>Modify the Dashboard configuration file, usually <code>/data/config.yaml</code>.</p></li><li><p>Set <code>web_real_ip_header</code> to an empty value or direct-IP mode:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><p>Or:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NZ::Use-Peer-IP&quot;</span></span></code></pre></div></li><li><p>Restart Dashboard.</p></li><li><p>Log in again, then go to <strong>System Settings → Web Application Firewall</strong> and delete the mistakenly blocked IP or related block entries.</p></li></ol><p>If you can already access the backend, you can also update <strong>Frontend Real IP Request Header</strong> directly in System Settings, save it, and then delete the related block entry on the WAF page.</p>`,57),r=[n];function o(l,h,d,p,c,u){return s(),a("div",null,r)}const y=e(i,[["render",o]]);export{k as __pageData,y as default};
